#nullable enable // autogenerated

using MukioI18n;
using MVZ2.GameContent.Contraptions;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Definitions;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Localization;
using MVZ2.Vanilla.RandomChina;
using MVZ2Logic.Entities;
using PVZEngine.Entities;
using Tools;

namespace MVZ2.GameContent.RandomChinaEvents
{
    [RandomChinaEventDefinition(VanillaRandomChinaEventNames.heavyContraption)]
    public class HeavyContraptionEvent : RandomChinaEventDefinition
    {
        public HeavyContraptionEvent(string nsp, string path) : base(nsp, path, NAME, DESCRIPTION)
        {
        }
        public override void Run(Entity contraption, RandomGenerator rng)
        {
            var level = contraption.Level;
            contraption.SpawnWithParams(VanillaContraptionID.snipenser, contraption.Position);
            contraption.Remove();
            contraption.PlaySound(VanillaSoundID.gunReload);
            contraption.PlaySound(VanillaSoundID.powerUp);
            contraption.PlaySound(VanillaSoundID.motor);
        }
        [TranslateMsg("随机瓷器事件名称", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_NAME)]
        public const string NAME = "重装器械";
        [TranslateMsg("随机瓷器事件描述", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_DESCRIPTION)]
        public const string DESCRIPTION = "变为狙击发射器";
    }
}
